def process_payment(
    user: dict,
    cart_items: list,
    payment_details: dict,
    client_discount: Optional[float] = None,
) -> dict:
    """
    Main payment processing function with server-side validation.

    Enforces:
    - Server-side user role lookup (never trusts client-supplied role)
    - Server-side price computation (never trusts client-supplied prices)
    - Server-side discount calculation (never trusts client-supplied discounts)
    - Strict state machine transitions for the payment workflow
    - Authorization checks at each step

    Args:
        user: Client-supplied user object (only user_id is trusted as a lookup key)
        cart_items: Client-supplied cart items (prices are recomputed server-side)
        payment_details: Payment method and token information
        client_discount: Any client-supplied discount (will be IGNORED)

    Returns:
        dict: Transaction result with all server-computed values
    """
    transaction = PaymentTransaction()

    try:
        # ============================================================
        # STEP 1: Server-side user authentication and authorization
        # ============================================================
        user_id = user.get("user_id") if isinstance(user, dict) else None
        if not user_id:
            raise AuthorizationError("Missing user_id in request.")

        # SECURITY: Look up user from trusted database, ignore client-supplied role
        trusted_user = _lookup_trusted_user(user_id)

        # SECURITY: Log if client tried to supply a different role
        client_role = user.get("role")
        if client_role and client_role != trusted_user["role"]:
            print(
                f"[SECURITY WARNING] User '{user_id}' sent role '{client_role}' "
                f"but trusted role is '{trusted_user['role']}'. Ignoring client role."
            )

        # Resolve role from trusted data only
        trusted_role = _resolve_trusted_role(trusted_user)

        # ============================================================
        # STEP 2: Validate cart items and recompute prices server-side
        # ============================================================
        # SECURITY: Precondition check - must be in PENDING state
        if transaction.status != PaymentStatus.PENDING:
            raise InvalidStateTransitionError("Transaction must be in PENDING state for validation.")

        validated_items, subtotal = _validate_and_price_cart_items(cart_items)

        # Validate payment details
        validated_payment = _validate_payment_details(payment_details)

        transaction.validated_user = trusted_user
        transaction.validated_items = validated_items
        transaction.subtotal = subtotal

        # Transition: PENDING -> VALIDATED
        transaction.transition_to(
            PaymentStatus.VALIDATED,
            f"Cart validated with {len(validated_items)} items, subtotal: ${subtotal}"
        )

        # ============================================================
        # STEP 3: Compute and apply discount server-side
        # ============================================================
        # SECURITY: Precondition check - must be in VALIDATED state
        if transaction.status != PaymentStatus.VALIDATED:
            raise InvalidStateTransitionError("Transaction must be VALIDATED before applying discounts.")

        # SECURITY: Ignore any client-supplied discount
        if client_discount is not None:
            print(
                f"[SECURITY WARNING] Client supplied discount of {client_discount}. "
                f"Ignoring and computing server-side discount for role '{trusted_role.value}'."
            )

        # Compute discount from server-side rules only
        discount_percentage = _compute_server_side_discount(trusted_role)
        discount_amount = round(subtotal * discount_percentage, 2)
        total = round(subtotal - discount_amount, 2)

        if total < 0:
            total = 0.0

        transaction.discount_percentage = discount_percentage
        transaction.discount_amount = discount_amount
        transaction.total = total

        # Transition: VALIDATED -> DISCOUNT_APPLIED
        transaction.transition_to(
            PaymentStatus.DISCOUNT_APPLIED,
            f"Discount {discount_percentage * 100}% applied for {trusted_role.value} user. "
            f"Discount: ${discount_amount}, Total: ${total}"
        )

        # ============================================================
        # STEP 4: Process payment
        # ============================================================
        # SECURITY: Precondition check - must be in DISCOUNT_APPLIED state
        if transaction.status != PaymentStatus.DISCOUNT_APPLIED:
            raise InvalidStateTransitionError("Transaction must have DISCOUNT_APPLIED before processing.")

        # SECURITY: Final verification - recompute total to prevent any tampering
        verified_total = round(subtotal - round(subtotal * discount_percentage, 2), 2)
        if abs(verified_total - total) > 0.01:
            raise PaymentProcessingError(
                f"Total verification failed. Expected ${verified_total}, got ${total}."
            )

        # Process payment through gateway
        gateway_result = _simulate_payment_gateway(total, validated_payment)

        if not gateway_result.get("success"):
            transaction.transition_to(
                PaymentStatus.FAILED,
                f"Payment gateway error: {gateway_result.get('error', 'Unknown error')}"
            )
            raise PaymentProcessingError(
                f"Payment failed: {gateway_result.get('error', 'Unknown error')}"
            )

        # Transition: DISCOUNT_APPLIED -> PROCESSED
        transaction.transition_to(
            PaymentStatus.PROCESSED,
            f"Payment of ${total} processed successfully via {validated_payment['method']}"
        )

        # ============================================================
        # Build and return result
        # ============================================================
        return {
            "success": True,
            "transaction_id": transaction.transaction_id,
            "status": transaction.status.value,
            "user": {
                "user_id": trusted_user["user_id"],
                "role": trusted_role.value,
                "email": trusted_user["email"],
            },
            "order_summary": {
                "items": validated_items,
                "subtotal": subtotal,
                "discount": {
                    "role": trusted_role.value,
                    "percentage": f"{discount_percentage * 100}%",
                    "amount": discount_amount,
                },
                "total": total,
            },
            "payment": {
                "method": validated_payment["method"],
                "gateway_transaction_id": gateway_result.get("gateway_transaction_id"),
                "amount_charged": gateway_result.get("amount_charged"),
                "currency": gateway_result.get("currency", "USD"),
            },
            "workflow_history": [
                {
                    "status": status.value,
                    "timestamp": ts.isoformat(),
                    "reason": reason,
                }
                for status, ts, reason in transaction.history
            ],
        }

    except (AuthorizationError, ValidationError, InvalidStateTransitionError, PaymentProcessingError) as e:
        # Ensure transaction is marked as failed if not already terminal
        if transaction.status not in (PaymentStatus.PROCESSED, PaymentStatus.FAILED):
            try:
                transaction.transition_to(PaymentStatus.FAILED, str(e))
            except InvalidStateTransitionError:
                pass

        return {
            "success": False,
            "transaction_id": transaction.transaction_id,
            "status": transaction.status.value,
            "error": str(e),
            "error_type": type(e).__name__,
            "workflow_history": [
                {
                    "status": status.value,
                    "timestamp": ts.isoformat(),
                    "reason": reason,
                }
                for status, ts, reason in transaction.history
            ],
        }


